/**
 * The request body the platform must send. Mirrors `hw_net::Body`.
 */

public enum Body {
    
    case empty
    case bytes(contentType: String, data: Data
    )
    case multipart(boundary: String, parts: [HwPart]
    )
    case fileStream(path: String, contentType: String
    )
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeBody: FfiConverterRustBuffer {
    typealias SwiftType = Body

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> Body {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .empty
        
        case 2: return .bytes(contentType: try FfiConverterString.read(from: &buf), data: try FfiConverterData.read(from: &buf)
        )
        
        case 3: return .multipart(boundary: try FfiConverterString.read(from: &buf), parts: try FfiConverterSequenceTypeHwPart.read(from: &buf)
        )
        
        case 4: return .fileStream(path: try FfiConverterString.read(from: &buf), contentType: try FfiConverterString.read(from: &buf)
        )
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: Body, into buf: inout [UInt8]) {
        switch value {
        
        
        case .empty:
            writeInt(&buf, Int32(1))
        
        
        case let .bytes(contentType,data):
            writeInt(&buf, Int32(2))
            FfiConverterString.write(contentType, into: &buf)
            FfiConverterData.write(data, into: &buf)
            
        
        case let .multipart(boundary,parts):
            writeInt(&buf, Int32(3))
            FfiConverterString.write(boundary, into: &buf)
            FfiConverterSequenceTypeHwPart.write(parts, into: &buf)
            
        
        case let .fileStream(path,contentType):
            writeInt(&buf, Int32(4))
            FfiConverterString.write(path, into: &buf)
            FfiConverterString.write(contentType, into: &buf)
            
        }
    }
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypeBody_lift(_ buf: RustBuffer) throws -> Body {
    return try FfiConverterTypeBody.lift(buf)
}

