public struct FfiConverterTypeHwPart: FfiConverterRustBuffer {
    typealias SwiftType = HwPart

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> HwPart {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .field(name: try FfiConverterString.read(from: &buf), value: try FfiConverterString.read(from: &buf)
        )
        
        case 2: return .fileRef(field: try FfiConverterString.read(from: &buf), path: try FfiConverterString.read(from: &buf), mime: try FfiConverterString.read(from: &buf), filename: try FfiConverterString.read(from: &buf)
        )
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: HwPart, into buf: inout [UInt8]) {
        switch value {
        
        
        case let .field(name,value):
            writeInt(&buf, Int32(1))
            FfiConverterString.write(name, into: &buf)
            FfiConverterString.write(value, into: &buf)
            
        
        case let .fileRef(field,path,mime,filename):
            writeInt(&buf, Int32(2))
            FfiConverterString.write(field, into: &buf)
            FfiConverterString.write(path, into: &buf)
            FfiConverterString.write(mime, into: &buf)
            FfiConverterString.write(filename, into: &buf)
            
        }
    }
}


