/**
 * Normalized transcription failures. Mirrors `hw_net::TranscriptionError` as a
 * UniFFI error enum. `Display` is implemented by hand (matching the leaf's
 * `thiserror` messages) so hw-core needs no extra dependency.
 */
public enum HwTranscriptionError {

    
    
    case Unauthorized
    case QuotaExceeded
    case FileTooLarge
    case RateLimited(retryAfterSecs: UInt64?
    )
    case ProviderUnavailable(status: UInt16
    )
    case NoSpeech
    case BadRequest(status: UInt16, message: String
    )
    case Parse(message: String
    )
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeHwTranscriptionError: FfiConverterRustBuffer {
    typealias SwiftType = HwTranscriptionError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> HwTranscriptionError {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        

        
        case 1: return .Unauthorized
        case 2: return .QuotaExceeded
        case 3: return .FileTooLarge
        case 4: return .RateLimited(
            retryAfterSecs: try FfiConverterOptionUInt64.read(from: &buf)
            )
        case 5: return .ProviderUnavailable(
            status: try FfiConverterUInt16.read(from: &buf)
            )
        case 6: return .NoSpeech
        case 7: return .BadRequest(
            status: try FfiConverterUInt16.read(from: &buf), 
            message: try FfiConverterString.read(from: &buf)
            )
        case 8: return .Parse(
            message: try FfiConverterString.read(from: &buf)
            )

         default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: HwTranscriptionError, into buf: inout [UInt8]) {
        switch value {

        

        
        
        case .Unauthorized:
            writeInt(&buf, Int32(1))
        
        
        case .QuotaExceeded:
            writeInt(&buf, Int32(2))
        
        
        case .FileTooLarge:
            writeInt(&buf, Int32(3))
        
        
        case let .RateLimited(retryAfterSecs):
            writeInt(&buf, Int32(4))
            FfiConverterOptionUInt64.write(retryAfterSecs, into: &buf)
            
        
        case let .ProviderUnavailable(status):
            writeInt(&buf, Int32(5))
            FfiConverterUInt16.write(status, into: &buf)
            
        
        case .NoSpeech:
            writeInt(&buf, Int32(6))
        
        
        case let .BadRequest(status,message):
            writeInt(&buf, Int32(7))
            FfiConverterUInt16.write(status, into: &buf)
            FfiConverterString.write(message, into: &buf)
            
        
        case let .Parse(message):
            writeInt(&buf, Int32(8))
            FfiConverterString.write(message, into: &buf)
            
        }
    }
}


extension HwTranscriptionError: Equatable, Hashable {}

extension HwTranscriptionError: Foundation.LocalizedError {
    public var errorDescription: String? {
        String(reflecting: self)
    }
}

